// // This module implements a 2-bit shift register with parallel load functionality. The shift register has an input for loading parallel data, a clock signal, a reset signal, and an output for the current state of the register. When the reset signal is high, the register should clear to FF. When the load signal is high, the data should be loaded into the register on the next clock edge. When the load signal is low, the register should shift right by one bit on the next clock edge.
module shift_register(  
    input clk,  
    input reset,  
    input load,  
    input [1:0] data_in,  
    output reg [1:0] q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            q <= 2'b00;  
        end else if (load) begin  
            q <= data_in;  
        end else begin  
            q <= {q[0], 1'b0};  
        end  
    end  
endmodule
